      referencias: [],
      historico: [{"versao":1,"texto":"As penas são:","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
