      paragrafos: [{"id":"cp:art-50-p1","numero":"1","texto":"A cobrança da multa pode efetuar-se mediante desconto no vencimento ou salário do condenado quando:","alineas":[{"id":"cp:art-50-p1-a","numero":"a","texto":"aplicada isoladamente;"},{"id":"cp:art-50-p1-b","numero":"b","texto":"aplicada cumulativamente com pena restritiva de direitos;"},{"id":"cp:art-50-p1-c","numero":"c","texto":"concedida a suspensão condicional da pena."}]},{"id":"cp:art-50-p2","numero":"2","texto":"O desconto não deve incidir sobre os recursos indispensáveis ao sustento do condenado e de sua família.","alineas":[]}],
      incisos: [],
