    {
      tipo: "artigo" as const,
      id: "cp:art-81",
      numero: "81",
      caput: "A suspensão será revogada se, no curso do prazo, o beneficiário:",
      paragrafos: [{"id":"cp:art-81-p1","numero":"1","texto":"A suspensão poderá ser revogada se o condenado descumpre qualquer outra condição imposta ou é irrecorrivelmente condenado, por crime culposo ou por contravenção, a pena privativa de liberdade ou restritiva de direitos.","alineas":[]},{"id":"cp:art-81-p2","numero":"2","texto":"Se o beneficiário está sendo processado por outro crime ou contravenção, considera-se prorrogado o prazo da suspensão até o julgamento definitivo.","alineas":[]},{"id":"cp:art-81-p3","numero":"3","texto":"Quando facultativa a revogação, o juiz pode, ao invés de decretá-la, prorrogar o período de prova até o máximo, se este não foi o fixado.","alineas":[]}],
      incisos: [{"id":"cp:art-81-inc-I","numero":"I","texto":"é condenado, em sentença irrecorrível, por crime doloso;","alineas":[]},{"id":"cp:art-81-inc-II","numero":"II","texto":"frustra, embora solvente, a execução de pena de multa ou não efetua, sem motivo justificado, a reparação do dano;","alineas":[]},{"id":"cp:art-81-inc-III","numero":"III","texto":"descumpre a condição do § 1º do art. 78 deste Código.","alineas":[]}],
      referencias: [],
      historico: [{"versao":1,"texto":"A suspensão será revogada se, no curso do prazo, o beneficiário:","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"Inc. I: é condenado, em sentença irrecorrível, por crime doloso;","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"Inc. II: frustra, embora solvente, a execução de pena de multa ou não efetua, sem motivo justificado, a reparação do dano;","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"Inc. III: descumpre a condição do § 1º do art. 78 deste Código.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":5,"texto":"§1: A suspensão poderá ser revogada se o condenado descumpre qualquer outra condição imposta ou é irrecorrivelmente condenado, por crime culposo ou por contravenção, a pena privativa de liberdade ou restritiva de direitos.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":6,"texto":"§2: Se o beneficiário está sendo processado por outro crime ou contravenção, considera-se prorrogado o prazo da suspensão até o julgamento definitivo.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":7,"texto":"§3: Quando facultativa a revogação, o juiz pode, ao invés de decretá-la, prorrogar o período de prova até o máximo, se este não foi o fixado.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
