      historico: [{"versao":1,"texto":"Expirado o prazo sem que tenha havido revogação, considera-se extinta a pena privativa de liberdade.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
