      id: "cp:art-92",
      numero: "92",
      caput: "São também efeitos da condenação:",
      paragrafos: [{"id":"cp:art-92-p1","numero":"1","texto":"Os efeitos de que trata este artigo não são automáticos, devendo ser motivadamente declarados na sentença pelo juiz, mas independem de pedido expresso da acusação, observado o disposto no inciso III do § 2º deste artigo.","alineas":[]},{"id":"cp:art-92-p2","numero":"2","texto":"Ao condenado por crime praticado contra a mulher por razões da condição do sexo feminino, nos termos do § 1º do art. 121-A deste Código serão:","alineas":[]}],
      incisos: [{"id":"cp:art-92-inc-I","numero":"I","texto":"a perda de cargo, função pública ou mandato eletivo:","alineas":[{"id":"cp:art-92-inc-I-a","numero":"a","texto":"quando aplicada pena privativa de liberdade por tempo igual ou superior a um ano, nos crimes praticados com abuso de poder ou violação de dever para com a Administração Pública;"},{"id":"cp:art-92-inc-I-b","numero":"b","texto":"quando for aplicada pena privativa de liberdade por tempo superior a 4 (quatro) anos nos demais casos."}]},{"id":"cp:art-92-inc-III","numero":"III","texto":"a inabilitação para dirigir veículo, quando utilizado como meio para a prática de crime doloso.","alineas":[]}],
      referencias: [],
      historico: [{"versao":1,"texto":"São também efeitos da condenação:","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"Inc. I: a perda de cargo, função pública ou mandato eletivo:","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 9.268, de 1º.4.1996","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"Inc. III: a inabilitação para dirigir veículo, quando utilizado como meio para a prática de crime doloso.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§1: Os efeitos de que trata este artigo não são automáticos, devendo ser motivadamente declarados na sentença pelo juiz, mas independem de pedido expresso da acusação, observado o disposto no inciso III do § 2º deste artigo.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.994, de 2024","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":5,"texto":"§2: Ao condenado por crime praticado contra a mulher por razões da condição do sexo feminino, nos termos do § 1º do art. 121-A deste Código serão:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.994, de 2024","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
