      id: "cp:art-100",
      numero: "100",
      caput: "A ação penal é pública, salvo quando a lei expressamente a declara privativa do ofendido.",
      paragrafos: [{"id":"cp:art-100-p1","numero":"1","texto":"A ação pública é promovida pelo Ministério Público, dependendo, quando a lei o exige, de representação do ofendido ou de requisição do Ministro da Justiça.","alineas":[]},{"id":"cp:art-100-p2","numero":"2","texto":"A ação de iniciativa privada é promovida mediante queixa do ofendido ou de quem tenha qualidade para representá-lo.","alineas":[]},{"id":"cp:art-100-p3","numero":"3","texto":"A ação de iniciativa privada pode intentar-se nos crimes de ação pública, se o Ministério Público não oferece denúncia no prazo legal.","alineas":[]},{"id":"cp:art-100-p4","numero":"4","texto":"No caso de morte do ofendido ou de ter sido declarado ausente por decisão judicial, o direito de oferecer queixa ou de prosseguir na ação passa ao cônjuge, ascendente, descendente ou irmão.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"A ação penal é pública, salvo quando a lei expressamente a declara privativa do ofendido.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: A ação pública é promovida pelo Ministério Público, dependendo, quando a lei o exige, de representação do ofendido ou de requisição do Ministro da Justiça.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: A ação de iniciativa privada é promovida mediante queixa do ofendido ou de quem tenha qualidade para representá-lo.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§3: A ação de iniciativa privada pode intentar-se nos crimes de ação pública, se o Ministério Público não oferece denúncia no prazo legal.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":5,"texto":"§4: No caso de morte do ofendido ou de ter sido declarado ausente por decisão judicial, o direito de oferecer queixa ou de prosseguir na ação passa ao cônjuge, ascendente, descendente ou irmão.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
