      id: "cp:art-106",
      numero: "106",
      caput: "O perdão, no processo ou fora dele, expresso ou tácito:",
      paragrafos: [{"id":"cp:art-106-p1","numero":"1","texto":"Perdão tácito é o que resulta da prática de ato incompatível com a vontade de prosseguir na ação.","alineas":[]},{"id":"cp:art-106-p2","numero":"2","texto":"Não é admissível o perdão depois que passa em julgado a sentença condenatória.","alineas":[]}],
