      caput: "A prescrição, antes de transitar em julgado a sentença final, salvo o disposto no § 1o do art. 110 deste Código, regula-se pelo máximo da pena privativa de liberdade cominada ao crime, verificando-se: .",
      paragrafos: [{"id":"cp:art-109-púnico","numero":"único","texto":"Aplicam-se às penas restritivas de direito os mesmos prazos previstos para as privativas de liberdade.","alineas":[]}],
      incisos: [{"id":"cp:art-109-inc-I","numero":"I","texto":"em vinte anos, se o máximo da pena é superior a doze;","alineas":[]},{"id":"cp:art-109-inc-II","numero":"II","texto":"em dezesseis anos, se o máximo da pena é superior a oito anos e não excede a doze;","alineas":[]},{"id":"cp:art-109-inc-III","numero":"III","texto":"em doze anos, se o máximo da pena é superior a quatro anos e não excede a oito;","alineas":[]},{"id":"cp:art-109-inc-IV","numero":"IV","texto":"em oito anos, se o máximo da pena é superior a dois anos e não excede a quatro;","alineas":[]},{"id":"cp:art-109-inc-V","numero":"V","texto":"em quatro anos, se o máximo da pena é igual a um ano ou, sendo superior, não excede a dois;","alineas":[]},{"id":"cp:art-109-inc-VI","numero":"VI","texto":"em 3 (três) anos, se o máximo da pena é inferior a 1 (um) ano. .","alineas":[]}],
      referencias: ["cp:art-110"],
      historico: [{"versao":1,"texto":"A prescrição, antes de transitar em julgado a sentença final, salvo o disposto no § 1o do art. 110 deste Código, regula-se pelo máximo da pena privativa de liberdade cominada ao crime, verificando-se: .","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 12.234, de 2010","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"Inc. VI: em 3 (três) anos, se o máximo da pena é inferior a 1 (um) ano. .","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 12.234, de 2010","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§único: Aplicam-se às penas restritivas de direito os mesmos prazos previstos para as privativas de liberdade.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 7.209, de 11.7.1984","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
