      numero: "116",
      caput: "Antes de passar em julgado a sentença final, a prescrição não corre:",
      paragrafos: [{"id":"cp:art-116-púnico","numero":"único","texto":"Depois de passada em julgado a sentença condenatória, a prescrição não corre durante o tempo em que o condenado está preso por outro motivo.","alineas":[]}],
      incisos: [{"id":"cp:art-116-inc-I","numero":"I","texto":"enquanto não resolvida, em outro processo, questão de que dependa o reconhecimento da existência do crime;","alineas":[]},{"id":"cp:art-116-inc-II","numero":"II","texto":"enquanto o agente cumpre pena no exterior;","alineas":[]},{"id":"cp:art-116-inc-III","numero":"III","texto":"na pendência de embargos de declaração ou de recursos aos Tribunais Superiores, quando inadmissíveis; e","alineas":[]},{"id":"cp:art-116-inc-IV","numero":"IV","texto":"enquanto não cumprido ou não rescindido o acordo de não persecução penal.","alineas":[]}],
