      historico: [{"versao":1,"texto":"Matar mulher por razões da condição do sexo feminino:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.994, de 2024","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: Considera-se que há razões da condição do sexo feminino quando o crime envolve:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.994, de 2024","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: A pena do feminicídio é aumentada de 1/3 (um terço) até a metade se o crime é praticado:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.994, de 2024","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§3: Comunicam-se ao coautor ou partícipe as circunstâncias pessoais elementares do crime previstas no § 1º deste artigo.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.994, de 2024","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
