      paragrafos: [{"id":"cp:art-154-A-p1","numero":"1","texto":"o Na mesma pena incorre quem produz, oferece, distribui, vende ou difunde dispositivo ou programa de computador com o intuito de permitir a prática da conduta definida no caput.  Vigência","alineas":[]},{"id":"cp:art-154-A-p2","numero":"2","texto":"Aumenta-se a pena de 1/3 (um terço) a 2/3 (dois terços) se da invasão resulta prejuízo econômico.","alineas":[]},{"id":"cp:art-154-A-p3","numero":"3","texto":"o Se da invasão resultar a obtenção de conteúdo de comunicações eletrônicas privadas, segredos comerciais ou industriais, informações sigilosas, assim definidas em lei, ou o controle remoto não autorizado do dispositivo invadido:  Vigência","alineas":[]},{"id":"cp:art-154-A-p4","numero":"4","texto":"o Na hipótese do § 3o, aumenta-se a pena de um a dois terços se houver divulgação, comercialização ou transmissão a terceiro, a qualquer título, dos dados ou informações obtidos.  Vigência","alineas":[]},{"id":"cp:art-154-A-p5","numero":"5","texto":"o Aumenta-se a pena de um terço à metade se o crime for praticado contra:  Vigência","alineas":[]}],
