    {
      tipo: "artigo" as const,
      id: "cp:art-158",
      numero: "158",
      caput: "Constranger alguém, mediante violência ou grave ameaça, e com o intuito de obter para si ou para outrem indevida vantagem econômica, a fazer, tolerar que se faça ou deixar de fazer alguma coisa: Pena - reclusão, de quatro a dez anos, e multa.",
      paragrafos: [{"id":"cp:art-158-p1","numero":"1","texto":"Se o crime é cometido por duas ou mais pessoas, ou com emprego de arma, aumenta-se a pena de um terço até metade.","alineas":[]},{"id":"cp:art-158-p2","numero":"2","texto":"Aplica-se à extorsão praticada mediante violência o disposto no § 3º do artigo anterior. Vide Lei nº 8.072, de 25.7.90","alineas":[]},{"id":"cp:art-158-p3","numero":"3","texto":"o Se o crime é cometido mediante a restrição da liberdade da vítima, e essa condição é necessária para a obtenção da vantagem econômica, a pena é de reclusão, de 6 (seis) a 12 (doze) anos, além da multa; se resulta lesão corporal grave ou morte, aplicam-se as penas previstas no art. 159, §§ 2o e 3o, respectivamente.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"§3: o Se o crime é cometido mediante a restrição da liberdade da vítima, e essa condição é necessária para a obtenção da vantagem econômica, a pena é de reclusão, de 6 (seis) a 12 (doze) anos, além da multa; se resulta lesão corporal grave ou morte, aplicam-se as penas previstas no art. 159, §§ 2o e 3o, respectivamente.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 11.923, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    },
    {
      tipo: "artigo" as const,
      id: "cp:art-159",
      numero: "159",
      caput: "Seqüestrar pessoa com o fim de obter, para si ou para outrem, qualquer vantagem, como condição ou preço do resgate: Vide Lei nº 8.072, de 25.7.90 Pena - reclusão, de oito a quinze anos..",
      paragrafos: [{"id":"cp:art-159-p1","numero":"1","texto":"o Se o seqüestro dura mais de 24 (vinte e quatro) horas, se o seqüestrado é menor de 18 (dezoito) ou maior de 60 (sessenta) anos, ou se o crime é cometido por bando ou quadrilha. Vide Lei nº 8.072, de 25.7.90","alineas":[]},{"id":"cp:art-159-p2","numero":"2","texto":"Se do fato resulta lesão corporal de natureza grave: Vide Lei nº 8.072, de 25.7.90","alineas":[]},{"id":"cp:art-159-p3","numero":"3","texto":"Se resulta a morte: Vide Lei nº 8.072, de 25.7.90","alineas":[]},{"id":"cp:art-159-p4","numero":"4","texto":"Se o crime é cometido em concurso, o concorrente que o denunciar à autoridade, facilitando a libertação do seqüestrado, terá sua pena reduzida de um a dois terços.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"Seqüestrar pessoa com o fim de obter, para si ou para outrem, qualquer vantagem, como condição ou preço do resgate: Vide Lei nº 8.072, de 25.7.90","redacaoDadaPor":{"lei":"Vide Lei nº 10.446, de 2002","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: o Se o seqüestro dura mais de 24 (vinte e quatro) horas, se o seqüestrado é menor de 18 (dezoito) ou maior de 60 (sessenta) anos, ou se o crime é cometido por bando ou quadrilha. Vide Lei nº 8.072, de 25.7.90","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 10.741, de 2003","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§4: Se o crime é cometido em concurso, o concorrente que o denunciar à autoridade, facilitando a libertação do seqüestrado, terá sua pena reduzida de um a dois terços.","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 9.269, de 1996","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
