      paragrafos: [{"id":"cp:art-161-p1","numero":"1","texto":"Na mesma pena incorre quem:","alineas":[]},{"id":"cp:art-161-p2","numero":"2","texto":"Se o agente usa de violência, incorre também na pena a esta cominada.","alineas":[]},{"id":"cp:art-161-p3","numero":"3","texto":"Se a propriedade é particular, e não há emprego de violência, somente se procede mediante queixa.","alineas":[]}],
      incisos: [{"id":"cp:art-161-inc-I","numero":"I","texto":"desvia ou represa, em proveito próprio ou de outrem, águas alheias;","alineas":[]},{"id":"cp:art-161-inc-II","numero":"II","texto":"invade, com violência a pessoa ou grave ameaça, ou mediante concurso de mais de duas pessoas, terreno ou edifício alheio, para o fim de esbulho possessório.","alineas":[]}],
