    {
      tipo: "artigo" as const,
      id: "cp:art-169",
      numero: "169",
      caput: "Apropriar-se alguém de coisa alheia vinda ao seu poder por erro, caso fortuito ou força da natureza: Pena - detenção, de um mês a um ano, ou multa.",
      paragrafos: [{"id":"cp:art-169-púnico","numero":"único","texto":"Na mesma pena incorre:","alineas":[]}],
      incisos: [{"id":"cp:art-169-inc-I","numero":"I","texto":"quem acha tesouro em prédio alheio e se apropria, no todo ou em parte, da quota a que tem direito o proprietário do prédio;","alineas":[]},{"id":"cp:art-169-inc-II","numero":"II","texto":"quem acha coisa alheia perdida e dela se apropria, total ou parcialmente, deixando de restituí-la ao dono ou legítimo possuidor ou de entregá-la à autoridade competente, dentro no prazo de quinze dias.","alineas":[]}],
      referencias: [],
      historico: [],
    }
