      id: "cp:art-175",
      numero: "175",
      caput: "Enganar, no exercício de atividade comercial, o adquirente ou consumidor:",
      paragrafos: [{"id":"cp:art-175-p1","numero":"1","texto":"Alterar em obra que lhe é encomendada a qualidade ou o peso de metal ou substituir, no mesmo caso, pedra verdadeira por falsa ou por outra de menor valor; vender pedra falsa por verdadeira; vender, como precioso, metal de ou outra qualidade:","alineas":[]},{"id":"cp:art-175-p2","numero":"2","texto":"É aplicável o disposto no art. 155, § 2º.","alineas":[]}],
      incisos: [{"id":"cp:art-175-inc-I","numero":"I","texto":"vendendo, como verdadeira ou perfeita, mercadoria falsificada ou deteriorada;","alineas":[]},{"id":"cp:art-175-inc-II","numero":"II","texto":"entregando uma mercadoria por outra:","alineas":[]}],
