      id: "cp:art-183-A",
      numero: "183-A",
      caput: "Nos crimes de que trata este Título, quando cometidos contra as instituições financeiras e os prestadores de serviço de segurança privada, de que trata o Estatuto da Segurança Privada e da Segurança das Instituições Financeiras, as penas serão aumentadas de 1/3 (um terço) até o dobro.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"Nos crimes de que trata este Título, quando cometidos contra as instituições financeiras e os prestadores de serviço de segurança privada, de que trata o Estatuto da Segurança Privada e da Segurança das Instituições Financeiras, as penas serão aumentadas de 1/3 (um terço) até o dobro.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 14.967, de 2024","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
