      paragrafos: [{"id":"cp:art-260-p1","numero":"1","texto":"Se do fato resulta desastre:","alineas":[]},{"id":"cp:art-260-p2","numero":"2","texto":"No caso de culpa, ocorrendo desastre:","alineas":[]},{"id":"cp:art-260-p3","numero":"3","texto":"Para os efeitos deste artigo, entende-se por estrada de ferro qualquer via de comunicação em que circulem veículos de tração mecânica, em trilhos ou por meio de cabo aéreo.","alineas":[]}],
      incisos: [{"id":"cp:art-260-inc-I","numero":"I","texto":"destruindo, danificando ou desarranjando, total ou parcialmente, linha férrea, material rodante ou de tração, obra-de-arte ou instalação;","alineas":[]},{"id":"cp:art-260-inc-II","numero":"II","texto":"colocando obstáculo na linha;","alineas":[]},{"id":"cp:art-260-inc-III","numero":"III","texto":"transmitindo falso aviso acerca do movimento dos veículos ou interrompendo ou embaraçando o funcionamento de telégrafo, telefone ou radiotelegrafia;","alineas":[]},{"id":"cp:art-260-inc-IV","numero":"IV","texto":"praticando outro ato de que possa resultar desastre:","alineas":[]}],
      referencias: [],
      historico: [],
