      paragrafos: [{"id":"cp:art-272-p1","numero":"1","texto":"A - Incorre nas penas deste artigo quem fabrica, vende, expõe à venda, importa, tem em depósito para vender ou, de qualquer forma, distribui ou entrega a consumo a substância alimentícia ou o produto falsificado, corrompido ou adulterado.","alineas":[]},{"id":"cp:art-272-p1","numero":"1","texto":"Está sujeito às mesmas penas quem pratica as ações previstas neste artigo em relação a bebidas, com ou sem teor alcoólico.","alineas":[]},{"id":"cp:art-272-p2","numero":"2","texto":"Se o crime é culposo:","alineas":[]}],
