      paragrafos: [{"id":"cp:art-290-púnico","numero":"único","texto":"O máximo da reclusão é elevado a doze anos e multa, se o crime é cometido por funcionário que trabalha na repartição onde o dinheiro se achava recolhido, ou nela tem fácil ingresso, em razão do cargo.","alineas":[]}],
