      caput: "Falsificar, fabricando-os ou alterando-os:",
      paragrafos: [{"id":"cp:art-296-p1","numero":"1","texto":"Incorre nas mesmas penas:","alineas":[]},{"id":"cp:art-296-p2","numero":"2","texto":"Se o agente é funcionário público, e comete o crime prevalecendo-se do cargo, aumenta-se a pena de sexta parte.","alineas":[]}],
      incisos: [{"id":"cp:art-296-inc-I","numero":"I","texto":"selo público destinado a autenticar atos oficiais da União, de Estado ou de Município;","alineas":[]},{"id":"cp:art-296-inc-II","numero":"II","texto":"selo ou sinal atribuído por lei a entidade de direito público, ou a autoridade, ou sinal público de tabelião:","alineas":[]},{"id":"cp:art-296-inc-I","numero":"I","texto":"quem faz uso do selo ou sinal falsificado;","alineas":[]},{"id":"cp:art-296-inc-II","numero":"II","texto":"quem utiliza indevidamente o selo ou sinal verdadeiro em prejuízo de outrem ou em proveito próprio ou alheio.","alineas":[]},{"id":"cp:art-296-inc-III","numero":"III","texto":"quem altera, falsifica ou faz uso indevido de marcas, logotipos, siglas ou quaisquer outros símbolos utilizados ou identificadores de órgãos ou entidades da Administração Pública.","alineas":[]}],
