      id: "cp:art-297",
      numero: "297",
      caput: "Falsificar, no todo ou em parte, documento público, ou alterar documento público verdadeiro: Pena - reclusão, de dois a seis anos, e multa.",
      paragrafos: [{"id":"cp:art-297-p1","numero":"1","texto":"Se o agente é funcionário público, e comete o crime prevalecendo-se do cargo, aumenta-se a pena de sexta parte.","alineas":[]},{"id":"cp:art-297-p2","numero":"2","texto":"Para os efeitos penais, equiparam-se a documento público o emanado de entidade paraestatal, o título ao portador ou transmissível por endosso, as ações de sociedade comercial, os livros mercantis e o testamento particular.","alineas":[]},{"id":"cp:art-297-p3","numero":"3","texto":"o Nas mesmas penas incorre quem insere ou faz inserir:","alineas":[]},{"id":"cp:art-297-p4","numero":"4","texto":"o Nas mesmas penas incorre quem omite, nos documentos mencionados no § 3o, nome do segurado e seus dados pessoais, a remuneração, a vigência do contrato de trabalho ou de prestação de serviços.","alineas":[]}],
      incisos: [{"id":"cp:art-297-inc-I","numero":"I","texto":"na folha de pagamento ou em documento de informações que seja destinado a fazer prova perante a previdência social, pessoa que não possua a qualidade de segurado obrigatório;","alineas":[]},{"id":"cp:art-297-inc-II","numero":"II","texto":"na Carteira de Trabalho e Previdência Social do empregado ou em documento que deva produzir efeito perante a previdência social, declaração falsa ou diversa da que deveria ter sido escrita;","alineas":[]},{"id":"cp:art-297-inc-III","numero":"III","texto":"em documento contábil ou em qualquer outro documento relacionado com as obrigações da empresa perante a previdência social, declaração falsa ou diversa da que deveria ter constado.","alineas":[]}],
      referencias: [],
      historico: [{"versao":1,"texto":"§3: o Nas mesmas penas incorre quem insere ou faz inserir:","redacaoDadaPor":{"lei":"Incluído pela Lei nº 9.983, de 2000","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"Inc. I: na folha de pagamento ou em documento de informações que seja destinado a fazer prova perante a previdência social, pessoa que não possua a qualidade de segurado obrigatório;","redacaoDadaPor":{"lei":"Incluído pela Lei nº 9.983, de 2000","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"Inc. II: na Carteira de Trabalho e Previdência Social do empregado ou em documento que deva produzir efeito perante a previdência social, declaração falsa ou diversa da que deveria ter sido escrita;","redacaoDadaPor":{"lei":"Incluído pela Lei nº 9.983, de 2000","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"Inc. III: em documento contábil ou em qualquer outro documento relacionado com as obrigações da empresa perante a previdência social, declaração falsa ou diversa da que deveria ter constado.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 9.983, de 2000","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":5,"texto":"§4: o Nas mesmas penas incorre quem omite, nos documentos mencionados no § 3o, nome do segurado e seus dados pessoais, a remuneração, a vigência do contrato de trabalho ou de prestação de serviços.","redacaoDadaPor":{"lei":"Incluído pela Lei nº 9.983, de 2000","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
